import React, { useState, useEffect, useCallback } from 'react';
import axios from 'axios';
import {
  ClipboardCheck, Check, X, Clock, CheckCircle, XCircle,
  Filter, Search, AlertTriangle, User
} from 'lucide-react';

const Aprovacoes = () => {
  const [aprovacoes, setAprovacoes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filtro, setFiltro] = useState('pendente');
  const [busca, setBusca] = useState('');
  const [motivoRejeicao, setMotivoRejeicao] = useState('');
  const [rejeitandoId, setRejeitandoId] = useState(null);

  const loadAprovacoes = useCallback(async () => {
    try {
      const res = await axios.get('/api/admin/aprovacoes');
      setAprovacoes(res.data || []);
    } catch (e) {
      console.error('Erro ao carregar aprovações:', e);
    } finally { setLoading(false); }
  }, []);

  useEffect(() => { loadAprovacoes(); }, [loadAprovacoes]);

  const handleAprovar = async (id) => {
    if (!window.confirm('Tem certeza que deseja aprovar esta solicitação?')) return;
    try {
      await axios.post(`/api/admin/aprovacoes/${id}/aprovar`);
      loadAprovacoes();
    } catch (err) {
      alert(err.response?.data?.detail || 'Erro ao aprovar');
    }
  };

  const handleRejeitar = async (id) => {
    try {
      await axios.post(`/api/admin/aprovacoes/${id}/rejeitar`, { motivo: motivoRejeicao });
      setRejeitandoId(null);
      setMotivoRejeicao('');
      loadAprovacoes();
    } catch (err) {
      alert(err.response?.data?.detail || 'Erro ao rejeitar');
    }
  };

  const filtradas = aprovacoes.filter(a => {
    const matchFiltro = filtro === 'todas' || a.status === filtro;
    const matchBusca = !busca ||
      (a.descricao || '').toLowerCase().includes(busca.toLowerCase()) ||
      (a.solicitante_nome || '').toLowerCase().includes(busca.toLowerCase()) ||
      (a.tipo || '').toLowerCase().includes(busca.toLowerCase());
    return matchFiltro && matchBusca;
  });

  const pendentes = aprovacoes.filter(a => a.status === 'pendente').length;

  const statusConfig = {
    pendente: { bg: 'bg-yellow-100', text: 'text-yellow-700', icon: Clock, label: 'Pendente' },
    aprovado: { bg: 'bg-green-100', text: 'text-green-700', icon: CheckCircle, label: 'Aprovado' },
    rejeitado: { bg: 'bg-red-100', text: 'text-red-700', icon: XCircle, label: 'Rejeitado' },
  };

  const tipoLabels = {
    giftcard_criar: 'Criar Gift Card',
    giftcard_ativar: 'Ativar Gift Card',
    pagamento: 'Pagamento',
    outro: 'Outro',
  };

  if (loading) return <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600" /></div>;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <ClipboardCheck className="h-7 w-7 text-orange-600" /> Aprovações
          </h1>
          <p className="text-sm text-gray-500 mt-1">
            Gerencie solicitações pendentes de aprovação
            {pendentes > 0 && <span className="ml-2 bg-yellow-100 text-yellow-700 px-2 py-0.5 rounded-full text-xs font-medium">{pendentes} pendente(s)</span>}
          </p>
        </div>
      </div>

      {/* Filters */}
      <div className="flex gap-3 flex-wrap">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
          <input type="text" placeholder="Buscar..." value={busca} onChange={e => setBusca(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg text-sm" />
        </div>
        <div className="flex gap-1 bg-gray-100 rounded-lg p-1">
          {[
            { value: 'pendente', label: 'Pendentes', color: 'text-yellow-700 bg-yellow-100' },
            { value: 'aprovado', label: 'Aprovadas', color: 'text-green-700 bg-green-100' },
            { value: 'rejeitado', label: 'Rejeitadas', color: 'text-red-700 bg-red-100' },
            { value: 'todas', label: 'Todas', color: 'text-gray-700 bg-white' },
          ].map(f => (
            <button key={f.value} onClick={() => setFiltro(f.value)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${filtro === f.value ? f.color + ' shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
              {f.label}
            </button>
          ))}
        </div>
      </div>

      {/* List */}
      {filtradas.length === 0 ? (
        <div className="text-center py-12">
          <ClipboardCheck className="h-12 w-12 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500">Nenhuma solicitação {filtro !== 'todas' ? filtro : ''}</p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtradas.map(a => {
            const sc = statusConfig[a.status] || statusConfig.pendente;
            const StatusIcon = sc.icon;
            return (
              <div key={a.id} className="bg-white rounded-lg shadow border border-gray-200 p-4">
                <div className="flex items-start justify-between gap-3">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className={`inline-flex items-center gap-1 text-xs px-2 py-0.5 rounded-full font-medium ${sc.bg} ${sc.text}`}>
                        <StatusIcon className="h-3 w-3" /> {sc.label}
                      </span>
                      <span className="text-xs bg-gray-100 text-gray-600 px-2 py-0.5 rounded-full">
                        {tipoLabels[a.tipo] || a.tipo}
                      </span>
                    </div>
                    <p className="text-sm font-medium text-gray-900">{a.descricao || 'Sem descrição'}</p>
                    <div className="flex items-center gap-3 mt-2 text-xs text-gray-500">
                      <span className="flex items-center gap-1">
                        <User className="h-3 w-3" /> {a.solicitante_nome} ({a.solicitante_cargo})
                      </span>
                      <span>{a.criado_em ? new Date(a.criado_em).toLocaleString('pt-BR') : ''}</span>
                    </div>

                    {a.status === 'aprovado' && (
                      <p className="text-xs text-green-600 mt-2 flex items-center gap-1">
                        <CheckCircle className="h-3 w-3" />
                        Aprovado por <strong>{a.aprovador_cargo}</strong>
                        {a.resolvido_em && ` em ${new Date(a.resolvido_em).toLocaleString('pt-BR')}`}
                      </p>
                    )}
                    {a.status === 'rejeitado' && (
                      <div className="mt-2">
                        <p className="text-xs text-red-600 flex items-center gap-1">
                          <XCircle className="h-3 w-3" />
                          Rejeitado por <strong>{a.aprovador_cargo}</strong>
                          {a.resolvido_em && ` em ${new Date(a.resolvido_em).toLocaleString('pt-BR')}`}
                        </p>
                        {a.motivo_rejeicao && <p className="text-xs text-red-500 mt-1 italic">Motivo: {a.motivo_rejeicao}</p>}
                      </div>
                    )}

                    {a.dados && Object.keys(a.dados).length > 0 && (
                      <details className="mt-2">
                        <summary className="text-xs text-gray-400 cursor-pointer hover:text-gray-600">Ver dados da solicitação</summary>
                        <pre className="mt-1 text-xs bg-gray-50 p-2 rounded overflow-auto max-h-32">{JSON.stringify(a.dados, null, 2)}</pre>
                      </details>
                    )}
                  </div>

                  {a.status === 'pendente' && (
                    <div className="flex flex-col gap-2 flex-shrink-0">
                      <button onClick={() => handleAprovar(a.id)}
                        className="flex items-center gap-1 bg-green-500 text-white px-3 py-1.5 rounded-lg text-xs font-medium hover:bg-green-600">
                        <Check className="h-3.5 w-3.5" /> Aprovar
                      </button>
                      <button onClick={() => { setRejeitandoId(a.id); setMotivoRejeicao(''); }}
                        className="flex items-center gap-1 bg-red-500 text-white px-3 py-1.5 rounded-lg text-xs font-medium hover:bg-red-600">
                        <X className="h-3.5 w-3.5" /> Rejeitar
                      </button>
                    </div>
                  )}
                </div>

                {/* Rejection reason modal */}
                {rejeitandoId === a.id && (
                  <div className="mt-3 p-3 bg-red-50 rounded-lg border border-red-200">
                    <p className="text-sm font-medium text-red-700 mb-2 flex items-center gap-1">
                      <AlertTriangle className="h-4 w-4" /> Motivo da rejeição
                    </p>
                    <textarea value={motivoRejeicao} onChange={e => setMotivoRejeicao(e.target.value)}
                      placeholder="Descreva o motivo..." rows={2}
                      className="w-full px-3 py-2 border border-red-200 rounded-lg text-sm mb-2" />
                    <div className="flex gap-2">
                      <button onClick={() => setRejeitandoId(null)}
                        className="px-3 py-1.5 border border-gray-300 rounded-lg text-xs text-gray-600 hover:bg-gray-50">Cancelar</button>
                      <button onClick={() => handleRejeitar(a.id)}
                        className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-xs font-medium hover:bg-red-700">Confirmar Rejeição</button>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default Aprovacoes;
